INSERT INTO "public"."goals" ("id", "company_id", "title", "description", "level", "status", "parent_id", "owner_agent_id", "created_at", "updated_at") VALUES ($paperclip$462a654a-c009-4734-bc21-508211efd923$paperclip$, $paperclip$712f694b-097f-4ca4-b161-f299187ec27d$paperclip$, $paperclip$Knowledge base in Obsidian voor het delen van kennis$paperclip$, $paperclip$We hebben nu een basis koppeling met Obsidian. Ik ben nieuw met obsidian maar waar ik naar op zoek ben is dat het Obsidian project niet heel druk is en ik duidelijk heb waar ik content moet plaatsen. Wat ik veel doe is dat als ik aan het praten ben in Webbio of we hebben een meeting met meerdere collega's dan neem ik hem op en heb ik het transcript. Dit transcript is vaak een goede bodem voor kennis welke ik uiteindelijk ook uit wil dragen. Ik wil dus deze transcripts en kennis delen in Obsidian zodat Rex het beste deze kennis tot zich kan nemen en daarover trend analyze doen. Dan hebben we uiteindelijk denk ik hele goede linkedIn voorstellen. Het kan zover gaan dat ik ook bronnen wil toevoegen bijvoorbeeld in Obsidian is het juist mooi omdat je referenties kan maken etc. en Ik wil dit optimaal benutten.

Als ik ook over zaken nog niet heb nagedacht lijkt me het goed om dit te onderzoeken.

Het algemene doel is dat we een goede werkbare content en knowledge pipeline hebben staan waar we uiteindelijk LinkedIn posts in Buffer.com mee vullen. Zodat we ons netwerk en zichtbaarheid uitbreiden op dat platform en in mijn professionele netwerk.$paperclip$, $paperclip$task$paperclip$, $paperclip$active$paperclip$, $paperclip$a85d1f2d-bd31-46a0-b36a-022c0ebb9921$paperclip$, NULL, $paperclip$2026-04-03T14:32:40.930Z$paperclip$, $paperclip$2026-04-03T14:35:37.416Z$paperclip$);
-- paperclip statement breakpoint 69f6f3f1-42fd-46a6-bf17-d1d85f8f3900

