e84034-4c31-4926-a145-8a1f713ba3fc\n  8db8080d-9064-4707-99c2-2e8d186f5e17\n  7d8b001d-912c-4f3d-a5f4-77195261fac8\n)\n\nsync_dir() {\n  local src=\"$1\" dst=\"$2\"\n  mkdir -p \"$dst\"\n\n  for item in \"$src\"/*(.N) \"$src\"/*(/.N); do\n    local base=\"${item:t}\"\n    local dst_item=\"$dst/$base\"\n\n    if [[ -d \"$item\" ]]; then\n      [[ -L \"$dst_item\" ]] && rm \"$dst_item\"\n      sync_dir \"$item\" \"$dst_item\"\n    else\n      if [[ -L \"$dst_item\" ]]; then\n        local existing=$(readlink \"$dst_item\")\n        [[ \"$existing\" = \"$item\" ]] && continue\n        rm \"$dst_item\"\n      elif [[ -e \"$dst_item\" ]]; then\n        continue\n      fi\n      ln -s \"$item\" \"$dst_item\"\n    fi\n  done\n}\n\nfor i in {1..${#AGENT_NAMES[@]}}; do\n  name=\"${AGENT_NAMES[$i]}\"\n  ws=\"$WORKSPACES/${AGENT_IDS[$i]}\"\n  [[ -d \"$ws\" ]] || continue\n  sync_dir \"$ws\" \"$VAULT/$name\"\ndone\n\necho \"Vault synced at $(date)\"\n","structuredPatch":[{"oldStart":1,"oldLines":4,"newStart":1,"newLines":4,"lines":["-#!/bin/bash","+#!/bin/zsh"," # Sync agent workspace files into the Obsidian vault"," # Replaces directory symlinks with real dirs + file symlinks"," # Run periodically or after agents create new files"]},{"oldStart":6,"oldLines":47,"newStart":6,"newLines":44,"lines":[" VAULT=\"$HOME/.paperclip/instances/default/vault\""," WORKSPACES=\"$HOME/.paperclip/instances/default/workspaces\""," ","-declare -A AGENTS=(","-  [\"Mitch\"]=\"467192bf-0ffd-49de-b18f-91a35b60e57a\"","-  [\"Nox\"]=\"23bc3620-04fa-40d0-8e4c-9a52ea800a9e\"","-  [\"Oscar\"]=\"d1e84034-4c31-4926-a145-8a1f713ba3fc\"","-  [\"Rex\"]=\"8db8080d-9064-4707-99c2-2e8d186f5e17\"","-  [\"Tommy\"]=\"7d8b001d-912c-4f3d-a5f4-77195261fac8\"","+# Agent name -> workspace UUID","+AGENT_NAMES=(Mitch Nox Oscar Rex Tommy)","+AGENT_IDS=(","+  467192bf-0ffd-49de-b18f-91a35b60e57a","+  23bc3620-04fa-40d0-8e4c-9a52ea800a9e","+  d1e84034-4c31-4926-a145-8a1f713ba3fc","+  8db8080d-9064-4707-99c2-2e8d186f5e17","+  7d8b001d-912c-4f3d-a5f4-77195261fac8"," )"," ","-shopt -s nullglob","-"," sync_dir() {","   local src=\"$1\" dst=\"$2\"","   mkdir -p \"$dst\""," ","-  for item in \"$src\"/*; do","-    local base=$(basename \"$item\")","+  for item in \"$src\"/*(.N) \"$src\"/*(/.N); do","+    local base=\"${item:t}\"","     local dst_item=\"$dst/$base\""," ","-    if [ -d \"$item\" ]; then","-      # Recurse into directories","-      if [ -L \"$dst_item\" ]; then","-        rm \"$dst_item\"","-      fi","+    if [[ -d \"$item\" ]]; then","+      [[ -L \"$dst_item\" ]] && rm \"$dst_item\"","       sync_dir \"$item\" \"$dst_item\"","     else","-      # Symlink files (skip if already linked correctly)","-      if [ -L \"$dst_item\" ]; then","+      if [[ -L \"$dst_item\" ]]; then","         local existing=$(readlink \"$dst_item\")","-        [ \"$existing\" = \"$item\" ] && continue","+        [[ \"$existing\" = \"$item\" ]] && continue","         rm \"$dst_item\"","-      elif [ -e \"$dst_item\" ]; then","-        continue  # real file exists, don't overwrite","+      elif [[ -e \"$dst_item\" ]]; then","+        continue","       fi","       ln -s \"$item\" \"$dst_item\"","     fi","   done"," }"," ","-for name in \"${!AGENTS[@]}\"; do","-  ws=\"$WORKSPACES/${AGENTS[$name]}\"","-  [ -d \"$ws\" ] || continue","+for i in {1..${#AGENT_NAMES[@]}}; do","+  name=\"${AGENT_NAMES[$i]}\"","+  ws=\"$WORKSPACES/${AGENT_IDS[$i]}\"","+  [[ -d \"$ws\" ]] || continue","   sync_dir \"$ws\" \"$VAULT/$name\""," done"," "]}],"originalFile":"#!/bin/bash\n# Sync agent workspace files into the Obsidian vault\n# Replaces directory symlinks with real dirs + file symlinks\n# Run periodically or after agents create new files\n\nVAULT=\"$HOME/.paperclip/instances/default/vault\"\nWORKSPACES=\"$HOME/.paperclip/instances/default/workspaces\"\n\ndeclare -A AGENTS=(\n  [\"Mitch\"]=\"467192bf-0ffd-49de-b18f-91a35b60e57a\"\n  [\"Nox\"]=\"23bc3620-04fa-40d0-8e4c-9a52ea800a9e\"\n  [\"Oscar\"]=\"d1e84034-4c31-4926-a145-8a1f713ba3fc\"\n  [\"Rex\"]=\"8db8080d-9064-4707-99c2-2e8d186f5e17\"\n  [\"Tommy\"]=\"7d8b001d-912c-4f3d-a5f4-77195261fac8\"\n)\n\nshopt -s nullglob\n\nsync_dir() {\n  local src=\"$1\" dst=\"$2\"\n  mkdir -p \"$dst\"\n\n  for item in \"$src\"/*; do\n    local base=$(basename \"$item\")\n    local dst_item=\"$dst/$base\"\n\n    if [ -d \"$item\" ]; then\n      # Recurse into directories\n      if [ -L \"$dst_item\" ]; then\n        rm \"$dst_item\"\n      fi\n      sync_dir \"$item\" \"$dst_item\"\n    else\n      # Symlink files (skip if already linked correctly)\n      if [ -L \"$dst_item\" ]; then\n        local existing=$(readlink \"$dst_item\")\n        [ \"$existing\" = \"$item\" ] && continue\n        rm \"$dst_item\"\n      elif [ -e \"$dst_item\" ]; then\n        continue  # real file exists, don't overwrite\n      fi\n      ln -s \"$item\" \"$dst_item\"\n    fi\n  done\n}\n\nfor name in \"${!AGENTS[@]}\"; do\n  ws=\"$WORKSPACES/${AGENTS[$name]}\"\n  [ -d \"$ws\" ] || continue\n  sync_dir \"$ws\" \"$VAULT/$name\"\ndone\n\necho \"Vault synced at $(date)\"\n"}}
