INSERT INTO "public"."issues" ("id", "company_id", "project_id", "goal_id", "parent_id", "title", "description", "status", "priority", "assignee_agent_id", "created_by_agent_id", "created_by_user_id", "request_depth", "billing_code", "started_at", "completed_at", "cancelled_at", "created_at", "updated_at", "issue_number", "identifier", "hidden_at", "checkout_run_id", "execution_run_id", "execution_agent_name_key", "execution_locked_at", "assignee_user_id", "assignee_adapter_overrides", "execution_workspace_settings", "project_workspace_id", "execution_workspace_id", "execution_workspace_preference", "origin_kind", "origin_id", "origin_run_id") VALUES ($paperclip$bb7aefcf-d00d-4f4f-91ee-7b0d955f2bc1$paperclip$, $paperclip$712f694b-097f-4ca4-b161-f299187ec27d$paperclip$, NULL, $paperclip$a85d1f2d-bd31-46a0-b36a-022c0ebb9921$paperclip$, $paperclip$7445a5b8-24ed-47d3-b4b5-50151b3238af$paperclip$, $paperclip$Weekly content cycle ŌĆö week of 2026-03-30$paperclip$, $paperclip$Run the weekly LinkedIn content cycle.

1. **Trend scan**: Search for trending AI/tech news relevant to Joeri's positioning (Dutch market, public sector, developer audience)
2. **Present hooks**: Comment with 2-3 content hooks, each with:
   - The news/trend angle
   - A draft post concept (3-4 sentences max)
   - Why it fits Joeri's voice and audience
3. **Wait for Joeri's pick**: Set task to blocked, ask Joeri to pick a hook and add his take (2-3 sentences)
4. **After Joeri responds**: Write the full post applying humanizer rules, stage in Buffer as draft
